class AuditLogger:
    """In-memory audit log. In production this would write to a DB table."""

    def __init__(self):
        self._log: list[AuditEntry] = []

    def record(
        self,
        event_type: AuditEventType,
        actor_id: Optional[int] = None,
        target_id: Optional[int] = None,
        detail: str = "",
    ) -> AuditEntry:
        entry = AuditEntry(
            event_type=event_type,
            actor_id=actor_id,
            target_id=target_id,
            detail=detail,
        )
        self._log.append(entry)
        return entry

    def get_events_for_user(self, user_id: int) -> list[AuditEntry]:
        return [e for e in self._log if e.actor_id == user_id]

    def get_events_for_target(self, target_id: int) -> list[AuditEntry]:
        return [e for e in self._log if e.target_id == target_id]

    def get_events_by_type(self, event_type: AuditEventType) -> list[AuditEntry]:
        return [e for e in self._log if e.event_type == event_type]

    def all_entries(self) -> list[AuditEntry]:
        return list(self._log)

def get_current_user(self, token: str) -> User:
        """Resolve a session token to a User. Raises AuthError if invalid."""
        user_id = self._sessions.get(token)
        if user_id is None:
            raise AuthError("Invalid or expired session token")
        user = self.db.get_user(user_id)
        if not user or not user.is_active:
            raise AuthError("User account is inactive")
        return user

    def logout(self, token: str) -> None:
        """Invalidate a session token."""
        self._sessions.pop(token, None)

class BillingService:
    """Enforces plan_tier limits before allowing resource-creating operations."""

    def __init__(self, db: Database):
        self.db = db

    def assign_plan(self, user: User, plan: PlanTier) -> None:
        _user_plans[user.id] = plan.value

    def get_plan(self, user: User) -> str:
        return _user_plans.get(user.id, PlanTier.FREE.value)

    def check_task_limit(self, user: User) -> None:
        """Raise BillingError if user has reached their plan_tier task cap."""
        plan = self.get_plan(user)
        limit = TASK_LIMITS.get(plan, TASK_LIMITS[PlanTier.FREE.value])
        current_count = len(self.db.list_tasks(owner_id=user.id))
        if current_count >= limit:
            raise BillingError(
                f"Task limit reached for plan '{plan}': {current_count}/{limit}. "
                "Upgrade your plan_tier to create more tasks."
            )

    def usage_summary(self, user: User) -> dict:
        plan = self.get_plan(user)
        limit = TASK_LIMITS.get(plan, TASK_LIMITS[PlanTier.FREE.value])
        used = len(self.db.list_tasks(owner_id=user.id))
        return {"plan_tier": plan, "tasks_used": used, "tasks_limit": limit}

class Database:
    """Simple in-memory store — a dict per table, keyed by id."""

    def __init__(self):
        self._users: dict[int, User] = {}
        self._tasks: dict[int, Task] = {}
        self._next_user_id = 1
        self._next_task_id = 1

    # ------------------------------------------------------------------
    # Users
    # ------------------------------------------------------------------

    def create_user(self, username: str, email: str) -> User:
        user = User(id=self._next_user_id, username=username, email=email)
        self._users[user.id] = user
        self._next_user_id += 1
        return user

    def get_user(self, user_id: int) -> Optional[User]:
        return self._users.get(user_id)

    def get_user_by_email(self, email: str) -> Optional[User]:
        for user in self._users.values():
            if user.email == email:
                return user
        return None

    def list_users(self) -> list[User]:
        return list(self._users.values())

    # ------------------------------------------------------------------
    # Tasks
    # ------------------------------------------------------------------

def create_task(
        self,
        title: str,
        description: str,
        owner_id: int,
        priority: Priority = Priority.MEDIUM,
        tags: list[str] = None,
    ) -> Task:
        task = Task(
            id=self._next_task_id,
            title=title,
            description=description,
            owner_id=owner_id,
            priority=priority,
            tags=tags or [],
        )
        self._tasks[task.id] = task
        self._next_task_id += 1
        return task

    def get_task(self, task_id: int) -> Optional[Task]:
        return self._tasks.get(task_id)

    def update_task_status(self, task_id: int, status: Status) -> Optional[Task]:
        task = self._tasks.get(task_id)
        if task:
            task.status = status
        return task

    def list_tasks(self, owner_id: Optional[int] = None) -> list[Task]:
        tasks = list(self._tasks.values())
        if owner_id is not None:
            tasks = [t for t in tasks if t.owner_id == owner_id]
        return tasks

    def delete_task(self, task_id: int) -> bool:
        if task_id in self._tasks:
            del self._tasks[task_id]
            return True
        return False

def search_tasks(self, keyword: str) -> list[Task]:
        """Search tasks by keyword in title or description (case-insensitive)."""
        keyword = keyword.lower()
        return [
            t for t in self._tasks.values()
            if keyword in t.title.lower() or keyword in t.description.lower()
        ]

"""
integrations/email_client.py — Thin SMTP wrapper.
In production this would use SendGrid / SES. Prints to stdout for demo.
"""

from dataclasses import dataclass


@dataclass
class EmailMessage:
    to_address: str
    subject: str
    body: str


class EmailClient:
    """Sends transactional emails. Swap send() for a real SMTP call in prod."""

    def __init__(self, from_address: str = "noreply@taskapp.dev"):
        self.from_address = from_address
        self._sent: list[EmailMessage] = []   # in-memory outbox for testing

    def send(self, message: EmailMessage) -> None:
        self._sent.append(message)
        print(
            f"[EMAIL] To: {message.to_address} | "
            f"Subject: {message.subject}"
        )

    def sent_messages(self) -> list[EmailMessage]:
        return list(self._sent)

"""
integrations/slack_webhook.py — Posts messages to a Slack channel via webhook.
Prints to stdout in demo mode (no real HTTP call).
"""


class SlackWebhook:
    """Wraps a Slack incoming webhook URL."""

    def __init__(self, webhook_url: str = "https://hooks.slack.com/demo"):
        self.webhook_url = webhook_url
        self._posted: list[str] = []   # captured messages for testing

    def post(self, text: str) -> None:
        self._posted.append(text)
        print(f"[SLACK] {text}")

    def posted_messages(self) -> list[str]:
        return list(self._posted)

class NotificationService:
    """Dispatches email + Slack notifications for task events."""

    def __init__(self, email_client: EmailClient, slack: SlackWebhook):
        self.email = email_client
        self.slack = slack

    def on_task_created(self, task: Task, owner: User) -> None:
        self.email.send(EmailMessage(
            to_address=owner.email,
            subject=f"Task created: {task.title}",
            body=(
                f"Hi {owner.username},\n\n"
                f"Your task '{task.title}' has been created "
                f"with priority '{task.priority.value}'.\n"
            ),
        ))
        self.slack.post(
            f":memo: New task by *{owner.username}*: {task.title} "
            f"[{task.priority.value}]"
        )

    def on_task_completed(self, task: Task, owner: User) -> None:
        self.email.send(EmailMessage(
            to_address=owner.email,
            subject=f"Task completed: {task.title}",
            body=(
                f"Hi {owner.username},\n\n"
                f"Great work! Task '{task.title}' has been marked as done.\n"
            ),
        ))
        self.slack.post(
            f":white_check_mark: Task completed by *{owner.username}*: {task.title}"
        )

    def on_task_deleted(self, task: Task, owner: User) -> None:
        self.slack.post(
            f":wastebasket: Task deleted by *{owner.username}*: {task.title}"
        )

def on_task_assigned(self, task: Task, assignee: User, assigner: User) -> None:
        self.email.send(EmailMessage(
            to_address=assignee.email,
            subject=f"Task assigned to you: {task.title}",
            body=(
                f"Hi {assignee.username},\n\n"
                f"{assigner.username} assigned you the task '{task.title}'.\n"
            ),
        ))
        self.slack.post(
            f":incoming_envelope: *{assigner.username}* assigned "
            f"'{task.title}' to *{assignee.username}*"
        )

"""
permissions.py — Role-based access control policy.
Defines what each role (admin, member, viewer) can do.
"""

from enum import Enum
from models import User


class Role(Enum):
    ADMIN = "admin"
    MEMBER = "member"
    VIEWER = "viewer"


# Maps role → set of allowed action strings
ROLE_PERMISSIONS: dict[str, set[str]] = {
    Role.ADMIN.value: {
        "task:create", "task:complete", "task:delete", "task:view",
        "task:assign", "report:view", "user:manage", "billing:view",
    },
    Role.MEMBER.value: {
        "task:create", "task:complete", "task:delete", "task:view",
        "report:view",
    },
    Role.VIEWER.value: {
        "task:view",
    },
}

# In-memory role store: user_id → role (default MEMBER)
_user_roles: dict[int, str] = {}


class PermissionError(Exception):
    pass

class PermissionPolicy:
    """Checks whether a user is allowed to perform a given action."""

    def assign_role(self, user: User, role: Role) -> None:
        _user_roles[user.id] = role.value

    def get_role(self, user: User) -> str:
        return _user_roles.get(user.id, Role.MEMBER.value)

    def require(self, user: User, action: str) -> None:
        """Raise PermissionError if user's role does not allow action."""
        role = self.get_role(user)
        allowed = ROLE_PERMISSIONS.get(role, set())
        if action not in allowed:
            raise PermissionError(
                f"User '{user.username}' with role '{role}' cannot perform '{action}'"
            )

    def can(self, user: User, action: str) -> bool:
        role = self.get_role(user)
        return action in ROLE_PERMISSIONS.get(role, set())

class ReportService:
    """Generates reports. Enforces report:view permission before returning data."""

    def __init__(self, db: Database, policy: PermissionPolicy):
        self.db = db
        self.policy = policy

    def user_report(self, requester: User, target_user_id: int) -> UserReport:
        self.policy.require(requester, "report:view")
        target = self.db.get_user(target_user_id)
        if target is None:
            raise ValueError(f"User {target_user_id} not found")
        tasks = self.db.list_tasks(owner_id=target_user_id)
        by_priority: dict[str, int] = {p.value: 0 for p in Priority}
        for t in tasks:
            by_priority[t.priority.value] += 1
        return UserReport(
            user_id=target.id,
            username=target.username,
            total_tasks=len(tasks),
            completed_tasks=sum(1 for t in tasks if t.status == Status.DONE),
            overdue_tasks=sum(1 for t in tasks if t.is_overdue()),
            tasks_by_priority=by_priority,
        )

def system_report(self, requester: User) -> SystemReport:
        self.policy.require(requester, "report:view")
        all_tasks = self.db.list_tasks()
        all_users = self.db.list_users()
        by_status: dict[str, int] = {s.value: 0 for s in Status}
        by_priority: dict[str, int] = {p.value: 0 for p in Priority}
        for t in all_tasks:
            by_status[t.status.value] += 1
            by_priority[t.priority.value] += 1
        return SystemReport(
            total_users=len(all_users),
            total_tasks=len(all_tasks),
            completed_tasks=by_status.get(Status.DONE.value, 0),
            tasks_by_status=by_status,
            tasks_by_priority=by_priority,
